protected function addResolveRecordMethodToClass(ClassType $class): void
    {
        $resolutionMode = $this->getResolutionMode();
        $resolutionColumn = $this->getResolutionColumn();

        $method = $class->addMethod('resolveRecord')
            ->setPublic()
            ->setReturnType(match ($resolutionMode) {
                'update' => "?{$this->getModelFqn()}",
                default => $this->getModelFqn(),
            })
            ->setBody(match ($resolutionMode) {
                'upsert' => new Literal(<<<PHP
                    return {$this->simplifyFqn($this->getModelFqn())}::firstOrNew([
                        ? => \$this->data[?],
                    ]);
                    PHP, [$resolutionColumn, $resolutionColumn]),
                'update' => new Literal(<<<PHP
                    return {$this->simplifyFqn($this->getModelFqn())}::query()
                        ->where(?, \$this->data[?])
                        ->first();
                    PHP, [$resolutionColumn, $resolutionColumn]),
                default => <<<PHP
                    return new {$this->simplifyFqn($this->getModelFqn())}();
                    PHP,
            });

        $this->configureResolveRecordMethod($method);
    }

public function getAuthorizationResponse(): Response
    {
        if ($this->authorization === null) {
            return $this->getHasActionsLivewire()->getDefaultActionAuthorizationResponse($this) ?? Response::allow();
        }

        if (! is_array($this->authorization)) {
            $response = $this->evaluate($this->authorization);

            return match (true) {
                $response instanceof Response => $response,
                (bool) $response => Response::allow(),
                default => Response::deny(),
            };
        }

        $abilities = $this->authorization['abilities'] ?? [];
        $arguments = $this->parseAuthorizationArguments($this->authorization['arguments'] ?? []);
        $type = $this->authorization['type'] ?? null;

        foreach ($abilities as $ability) {
            $response = Gate::inspect($ability, Arr::wrap($arguments));

            if (($type === 'any') && $response->allowed()) {
                return $response;
            }

            if (($type === 'all') && $response->denied()) {
                return $response;
            }
        }

        return Response::allow();
    }

