public function get(mixed $state): string | array
    {
        $editor = $this->richEditor->getTipTapEditor()
            ->setContent($state ?? [
                'type' => 'doc',
                'content' => [],
            ]);

        if ($this->richEditor->getFileAttachmentsVisibility() === 'private') {
            $editor->descendants(function (object &$node): void {
                if ($node->type !== 'image') {
                    return;
                }

                if (blank($node->attrs->id ?? null)) {
                    return;
                }

                if (blank($node->attrs->src ?? null)) {
                    return;
                }

                $node->attrs->src = null;
            });
        }

        if ($this->richEditor->getCustomBlocks()) {
            $editor->descendants(function (object &$node): void {
                if ($node->type !== 'customBlock') {
                    return;
                }

                unset($node->attrs->label);
                unset($node->attrs->preview);
                unset($node->attrs->shouldApplyProseStylingToPreview);
            });
        }

        return $editor->{$this->richEditor->isJson() ? 'getDocument' : 'getHtml'}();
    }

public function renderHTML($mark, $HTMLAttributes = []): array
    {
        $existingClass = isset($HTMLAttributes['class']) ? (string) $HTMLAttributes['class'] : '';
        $HTMLAttributes['class'] = trim(implode(' ', array_filter(['color', $existingClass])));

        $colorName = $HTMLAttributes['data-color'] ?? null;
        $colors = $this->options['textColors'] ?? [];
        $config = is_string($colorName) ? ($colors[$colorName] ?? null) : null;

        if ($config instanceof TextColor) {
            $cssVars = "--color: {$config->getColor()}; --dark-color: {$config->getDarkColor()}";
        } elseif (filled($colorName) && preg_match('/^[\sA-Za-z0-9.,%\/+\-#_()]+$/', (string) $colorName)) {
            $cssVars = "--color: {$colorName}; --dark-color: {$colorName}";
        } else {
            $cssVars = null;
        }

        if (filled($cssVars)) {
            $existingStyle = isset($HTMLAttributes['style']) ? (string) $HTMLAttributes['style'] : '';
            $HTMLAttributes['style'] = $existingStyle !== '' ? ($cssVars . '; ' . $existingStyle) : $cssVars;
        }

        return [
            'span',
            $HTMLAttributes,
            0,
        ];
    }

