protected function sendEmailChangeVerification(Model $record, string $newEmail): void
    {
        if ($record->getAttributeValue('email') === $newEmail) {
            return;
        }

        $notification = app(VerifyEmailChange::class);
        $notification->url = Filament::getVerifyEmailChangeUrl($record, $newEmail);

        $verificationSignature = Query::new($notification->url)->get('signature');

        cache()->put($verificationSignature, true, ttl: now()->addHour());

        $record->notify(app(NoticeOfEmailChangeRequest::class, [/** @phpstan-ignore-line */
            'blockVerificationUrl' => Filament::getBlockEmailChangeVerificationUrl($record, $newEmail, $verificationSignature),
            'newEmail' => $newEmail,
        ]));

        $newEmailRecipient = $this->getEmailChangeVerificationRecipientWithNewEmail($record, $notification, $newEmail);

        if ($record instanceof HasLocalePreference) {
            $notification->locale($record->preferredLocale());
        }

        Notification::route('mail', $newEmailRecipient)
            ->notify($notification);

        $this->getEmailChangeVerificationSentNotification($newEmail)?->send();

        $this->data['email'] = $record->getAttributeValue('email');
    }

protected function configureLocation(): void
    {
        $basename = (string) str($this->relationship)
            ->studly()
            ->append('RelationManager');

        $pluralResourceBasenameBeforeResource = (string) str($this->resourceFqn)
            ->classBasename()
            ->beforeLast('Resource')
            ->plural();

        $resourceNamespacePartBeforeBasename = (string) str($this->resourceFqn)
            ->beforeLast('\\')
            ->classBasename();

        if ($pluralResourceBasenameBeforeResource === $resourceNamespacePartBeforeBasename) {
            $this->fqn = (string) str($this->resourceFqn)
                ->beforeLast('\\')
                ->append("\\RelationManagers\\{$basename}");
            $this->path = (string) str((new ReflectionClass($this->resourceFqn))->getFileName())
                ->beforeLast(DIRECTORY_SEPARATOR)
                ->append("/RelationManagers/{$basename}.php");

            return;
        }

        $this->fqn = "{$this->resourceFqn}\\RelationManagers\\{$basename}";
        $this->path = (string) str((new ReflectionClass($this->resourceFqn))->getFileName())
            ->beforeLast('.')
            ->append("/RelationManagers/{$basename}.php");
    }

public function getNavigation(): array
    {
        $items = array_filter(
            $this->items,
            fn (NavigationItem $item): bool => $item->isVisible(),
        );

        return collect($this->groups)
            ->filter(function (NavigationGroup $group): bool {
                $visibleGroupItems = array_filter(
                    $group->getItems(),
                    fn (NavigationItem $item): bool => $item->isVisible(),
                );

                if (empty($visibleGroupItems)) {
                    return false;
                }

                $group->items($visibleGroupItems);

                return true;
            })
            ->when(
                count($items),
                fn (Collection $groups): Collection => $groups->prepend(
                    NavigationGroup::make()->items($items),
                ),
            )
            ->all();
    }

public function mountNavigation(): void
    {
        foreach ($this->panel->getPages() as $page) {
            $page::registerNavigationItems();
        }

        foreach ($this->panel->getPageConfigurations() as $configuration) {
            Filament::setCurrentPageConfigurationKey($configuration->getKey());

            $configuration->page::registerNavigationItems();

            Filament::setCurrentPageConfigurationKey(null);
        }

        foreach ($this->panel->getResources() as $resource) {
            $resource::registerNavigationItems();
        }

        foreach ($this->panel->getResourceConfigurations() as $configuration) {
            Filament::setCurrentResourceConfigurationKey($configuration->getKey());

            $configuration->resource::registerNavigationItems();

            Filament::setCurrentResourceConfigurationKey(null);
        }

        $this->isNavigationMounted = true;
    }

